#include <stdio.h>

typedef struct {
    unsigned int source_address;
    unsigned int dest_address;
    unsigned int transfer_count;
    unsigned int control_register;
} DMA_Controller;

#define DMA_START 0x01
#define DMA_READ  0x02
#define DMA_WRITE 0x04
#define DMA_DONE  0x10

void dma_init(DMA_Controller *dma) {
    dma->control_register = 0;
    printf("DMA Controller initialized.\n");
}

void dma_setup_transfer(DMA_Controller *dma, unsigned int src, 
                        unsigned int dest, unsigned int count) {
    dma->source_address = src;
    dma->dest_address = dest;
    dma->transfer_count = count;
    printf("DMA transfer setup: %u bytes from 0x%X to 0x%X\n", 
           count, src, dest);
}

void dma_start_transfer(DMA_Controller *dma) {
    dma->control_register = DMA_START | DMA_READ;
    printf("DMA transfer started (CPU now free for other tasks)...\n");

    // Simulate hardware DMA transfer
    printf("DMA: Transferring data directly to memory...\n");
    printf("DMA: Transfer complete! Interrupt generated.\n");

    dma->control_register = DMA_DONE;
}

void cpu_task(const char *task_name) {
    printf("CPU: Executing %s (parallel to DMA)\n", task_name);
}

int main() {
    DMA_Controller dma;

    printf("=== DMA Transfer Demonstration ===\n\n");

    // Setup DMA transfer
    dma_init(&dma);
    dma_setup_transfer(&dma, 0x8000, 0xC000, 1024);

    // Start DMA and CPU works in parallel
    dma_start_transfer(&dma);

    // CPU can perform other tasks while DMA transfers
    cpu_task("user application");
    cpu_task("background service");

    printf("\nDMA transfer efficiency: CPU saved from %d memory operations\n", 
           1024);

    return 0;
}
